import React, { useState, useEffect, useCallback } from "react";
import "./DisplayRows.css";

function ParameterDisplay(props) {
  // Use 'var' and avoid destructuring for 2016 browser stability
  var parameters = props.parameters || [];
  var onPageChange = props.onPageChange;
  var onFocusChange = props.onFocusChange;
  var activeFocus = props.activeFocus;
  var setAutoModeExternal = props.setAutoModeExternal;

  var [data, setData] = useState({});
  var [autoMode, setAutoMode] = useState(false);
  var [activeIndex, setActiveIndex] = useState(0);

  useEffect(function() {
    if (activeFocus !== undefined && activeFocus !== null && activeFocus >= 0 && activeFocus < parameters.length) {
      setActiveIndex(activeFocus);
    }
  }, [activeFocus, parameters.length]);

  var fetchParameters = useCallback(function() {
    var cacheBuster = new Date().getTime();

    // Using strictly lowercase 'parameters.json' for Linux compatibility
    fetch('/parameters.json?t=' + cacheBuster)
      .then(function(response) {
        if (!response.ok) throw new Error("File not found");
        return response.json();
      })
      .then(function(jsonArray) {
        if (!jsonArray || !Array.isArray(jsonArray)) return;

        // Metadata extraction
        var pageData = jsonArray.find(function(obj) { return obj && obj.page !== undefined; });
        if (pageData && onPageChange) onPageChange(pageData.page);

        var focusData = jsonArray.find(function(obj) { return obj && obj.focus !== undefined; });
        if (focusData && onFocusChange) onFocusChange(focusData.focus);

        var autoModeEntry = jsonArray.find(function(obj) { return obj && obj.autoMode !== undefined; });
        if (autoModeEntry !== undefined) {
          setAutoMode(autoModeEntry.autoMode);
          if (setAutoModeExternal) setAutoModeExternal(autoModeEntry.autoMode);
        }

        var formattedData = {};
        jsonArray.forEach(function(item) { 
          if (item && item.key) { formattedData[item.key] = item.value; }
        });
        setData(formattedData);
      })
      .catch(function(err) {
        console.log("CONSOLE: Fetch error - " + err.message);
      });
  }, [onPageChange, onFocusChange, setAutoModeExternal]);

  useEffect(function() {
    fetchParameters();
    var id = setInterval(fetchParameters, 200);
    return function() { clearInterval(id); };
  }, [fetchParameters]);

  if (autoMode) {
    return (
      <div className="parameter-rows-wrapper">
        <div className="autonomous-mode-overlay"><h2>AUTONOMOUS MODE ACTIVE</h2></div>
      </div>
    );
  }

  // If the array is empty or the fetch hasn't finished, show a status
  if (!parameters || parameters.length === 0) {
    return <div className="parameter-rows-wrapper">Waiting for racing data...</div>;
  }

  return (
    <div className="parameter-rows-wrapper">
      {/* .slice(6) skips metadata, .map handles the display */}
      {parameters.slice(6).map(function(param, index) {
        if (!param) return null;

        var val = data[param.key];
        var displayValue = (val !== undefined && val !== null) ? val : "---";

        // Offset index by 6 because we sliced the first 6 items
        var isFocused = (index + 6 === activeIndex);

        return (
          /* FIX: The 'key' prop here stops the error in your screenshot */
          <div key={param.key || index} className={"parameter-row " + (isFocused ? "focused" : "")}>
            <div className="parameter-label">{param.label || "No Label"}</div>
            <div className="parameter-value">{displayValue}</div>
          </div>
        );
      })}
    </div>
  );
}

export default ParameterDisplay;
